      // sword base: 100 G, first insurance surcharge: +10% = 110 G, processing fee: +5 G = 115 G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it.todo("should quote each main item type at its correct base premium");
    it.todo("should quote a single component at 25 G base premium plus processing fee");
    it.todo("should apply a special base premium of 60 G for a building block of 3 alike components");
    it.todo("should add 50% risk surcharge for cursed items");
    it.todo("should add 30% risk surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should give a 20% loyalty discount to long-standing customers (>= 2 years)");
    it.todo("should add a 10% initial assessment surcharge on the first insurance");
    it.todo("should give a 15% discount on each contract after the first");
    it.todo("should add a 5 G processing fee to every premium");
    it.todo("should round premium up to whole G in MHPCO's favor");
  });

  describe("Processing a claim", () => {
    it.todo("should apply a 100 G deductible per damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to high enchantment items (>= 8) at 50% of damage amount");
    it.todo("should fully reimburse damage to items made of dragon material");
    it.todo("should round payout down to whole G in MHPCO's favor");
    it.todo("should track remaining cap after each claim");
  });
});

