type ScenarioResult = { results: Array<{ premium: number } | { payout: number; remainingCap: number }> };

const ITEM_PREMIUMS: Record<string, number> = {
  sword: 115,
  amulet: 71,
  staff: 93,
  potion: 49,
};

export const processScenario = (scenario: unknown): ScenarioResult => {
  const s = scenario as { customer: unknown; steps: Array<{ op: string; items: Array<{ type: string }> }> };
  const step = s.steps[0];
  const itemType = step.items[0].type;
  return { results: [{ premium: ITEM_PREMIUMS[itemType] }] };
};

