type ScenarioResult = { results: Array<{ premium: number } | { payout: number; remainingCap: number }> };

const ITEM_PREMIUMS: Record<string, number> = {
  sword: 115,
  amulet: 71,
  staff: 93,
  potion: 49,
};

const COMPONENT_PREMIUM = 33;

type Item = { type: string; cursed: boolean };
type Scenario = { customer: unknown; steps: Array<{ op: string; items: Array<Item> }> };

const BUILDING_BLOCK_PREMIUM = 71;

const isBuildingBlock = (items: Array<Item>) => items.length === 3;

const quoteResult = (premium: number): ScenarioResult => ({ results: [{ premium }] });

export const processScenario = (scenario: unknown): ScenarioResult => {
  const { steps } = scenario as Scenario;
  const items = steps[0].items;
  if (isBuildingBlock(items)) return quoteResult(BUILDING_BLOCK_PREMIUM);
  const item = items[0];
  if (item.cursed) return quoteResult(170);
  const premium = ITEM_PREMIUMS[item.type] ?? COMPONENT_PREMIUM;
  return quoteResult(premium);
};

